args.sparql:
SELECT ?manager ?managerLabel WHERE {
  wd:Q1059415 p:P286 ?statement.
  ?statement ps:P286 ?manager.
  ?manager rdfs:label ?managerLabel.
  FILTER(LANG(?managerLabel) = "en")
}

SELECT ?manager ?managerLabel WHERE {
  wd:Q1059415 p:P286 ?statement.
  ?statement ps:P286 ?manager.
  ?statement pq:P580 ?start.
  OPTIONAL { ?statement pq:P582 ?end }
  ?manager rdfs:label ?managerLabel.
  FILTER(LANG(?managerLabel) = "en")
  FILTER(?start <= "2018-05-31"^^xsd:date)
  FILTER(!BOUND(?end) || ?end >= "2017-08-01"^^xsd:date)
}
